+    let tilde = '\u{0303}'; // combining tilde
+    let circumflex = '\u{0302}'; // combining circumflex
+
+    crate::assert_with_log!(char_width(acute) == 0, "acute width", 0usize, char_width(acute));
+    crate::assert_with_log!(char_width(tilde) == 0, "tilde width", 0usize, char_width(tilde));
